// ---- Combining Room and ViewModel ----

// ---- Entity ----
@Entity(tableName = "notes")
data class Note(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,
    val title: String,
    val content: String,
    val timestamp: Long = System.currentTimeMillis(),
    val isFavorite: Boolean = false,
    val color: Int? = null
)

// ---- DAO ----
@Dao
interface NoteDao {
    @Insert
    suspend fun insertNote(note: Note): Long

    @Query("SELECT * FROM notes ORDER BY timestamp DESC")
    fun getAllNotes(): Flow<List<Note>>

    @Query("SELECT * FROM notes WHERE id = :id")
    suspend fun getNoteById(id: Int): Note?

    @Query("SELECT * FROM notes WHERE isFavorite = 1")
    fun getFavoriteNotes(): Flow<List<Note>>

    @Query("SELECT * FROM notes WHERE title LIKE '%' || :query || '%' OR content LIKE '%' || :query || '%'")
    fun searchNotes(query: String): Flow<List<Note>>

    @Update
    suspend fun updateNote(note: Note)

    @Delete
    suspend fun deleteNote(note: Note)

    @Query("DELETE FROM notes WHERE id = :id")
    suspend fun deleteNoteById(id: Int)
}

// ---- Database ----
@Database(
    entities = [Note::class],
    version = 1,
    exportSchema = false
)
abstract class NoteDatabase : RoomDatabase() {
    abstract fun noteDao(): NoteDao

    companion object {
        @Volatile
        private var INSTANCE: NoteDatabase? = null

        fun getInstance(context: Context): NoteDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    NoteDatabase::class.java,
                    "notes_database"
                ).build()
                INSTANCE = instance
                instance
            }
        }
    }
}

// ---- Repository ----
class NoteRepository(
    private val dao: NoteDao
) {
    fun getAllNotes(): Flow<List<Note>> = dao.getAllNotes()

    fun getFavoriteNotes(): Flow<List<Note>> = dao.getFavoriteNotes()

    fun searchNotes(query: String): Flow<List<Note>> = dao.searchNotes(query)

    suspend fun getNoteById(id: Int): Note? = dao.getNoteById(id)

    suspend fun insertNote(title: String, content: String, isFavorite: Boolean = false): Long {
        val note = Note(
            title = title,
            content = content,
            isFavorite = isFavorite
        )
        return dao.insertNote(note)
    }

    suspend fun updateNote(note: Note) = dao.updateNote(note)

    suspend fun toggleFavorite(id: Int) {
        val note = dao.getNoteById(id) ?: return
        dao.updateNote(note.copy(isFavorite = !note.isFavorite))
    }

    suspend fun deleteNote(note: Note) = dao.deleteNote(note)

    suspend fun deleteNoteById(id: Int) = dao.deleteNoteById(id)
}

// ---- Use Cases ----
class GetNotesUseCase(
    private val repository: NoteRepository
) {
    operator fun invoke(): Flow<List<Note>> = repository.getAllNotes()
}

class GetFavoriteNotesUseCase(
    private val repository: NoteRepository
) {
    operator fun invoke(): Flow<List<Note>> = repository.getFavoriteNotes()
}

class SearchNotesUseCase(
    private val repository: NoteRepository
) {
    operator fun invoke(query: String): Flow<List<Note>> = repository.searchNotes(query)
}

class AddNoteUseCase(
    private val repository: NoteRepository
) {
    suspend operator fun invoke(title: String, content: String, isFavorite: Boolean = false): Long {
        return repository.insertNote(title, content, isFavorite)
    }
}

class UpdateNoteUseCase(
    private val repository: NoteRepository
) {
    suspend operator fun invoke(note: Note) = repository.updateNote(note)
}

class ToggleFavoriteUseCase(
    private val repository: NoteRepository
) {
    suspend operator fun invoke(id: Int) = repository.toggleFavorite(id)
}

class DeleteNoteUseCase(
    private val repository: NoteRepository
) {
    suspend operator fun invoke(note: Note) = repository.deleteNote(note)
}

// ---- ViewModel with Room ----
@HiltViewModel
class NoteViewModel @Inject constructor(
    private val getNotes: GetNotesUseCase,
    private val getFavorites: GetFavoriteNotesUseCase,
    private val searchNotes: SearchNotesUseCase,
    private val addNote: AddNoteUseCase,
    private val updateNote: UpdateNoteUseCase,
    private val toggleFavorite: ToggleFavoriteUseCase,
    private val deleteNote: DeleteNoteUseCase
) : ViewModel() {

    data class UiState(
        val notes: List<Note> = emptyList(),
        val filteredNotes: List<Note> = emptyList(),
        val selectedNote: Note? = null,
        val isShowingFavorites: Boolean = false,
        val searchQuery: String = "",
        val isLoading: Boolean = false,
        val error: String? = null
    )

    private val _uiState = MutableStateFlow(UiState())
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    init {
        loadNotes()
    }

    private fun loadNotes() {
        viewModelScope.launch {
            getNotes().collect { notes ->
                _uiState.update { state ->
                    val filtered = if (state.isShowingFavorites) {
                        notes.filter { it.isFavorite }
                    } else {
                        notes
                    }.filter {
                        state.searchQuery.isEmpty() ||
                        it.title.contains(state.searchQuery, ignoreCase = true) ||
                        it.content.contains(state.searchQuery, ignoreCase = true)
                    }
                    state.copy(
                        notes = notes,
                        filteredNotes = filtered
                    )
                }
            }
        }
    }

    fun toggleFavorites() {
        _uiState.update { state ->
            val newShowing = !state.isShowingFavorites
            state.copy(isShowingFavorites = newShowing)
        }
        applyFilters()
    }

    fun search(query: String) {
        _uiState.update { state ->
            state.copy(searchQuery = query)
        }
        applyFilters()
    }

    private fun applyFilters() {
        val state = _uiState.value
        val filtered = state.notes.filter { note ->
            (if (state.isShowingFavorites) note.isFavorite else true) &&
            (state.searchQuery.isEmpty() ||
            note.title.contains(state.searchQuery, ignoreCase = true) ||
            note.content.contains(state.searchQuery, ignoreCase = true))
        }
        _uiState.update { it.copy(filteredNotes = filtered) }
    }

    fun addNote(title: String, content: String) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                addNote(title, content)
                _uiState.update { it.copy(isLoading = false) }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun updateNote(note: Note) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                updateNote(note)
                _uiState.update { it.copy(isLoading = false) }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun toggleFavorite(id: Int) {
        viewModelScope.launch {
            try {
                toggleFavorite(id)
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message)
                }
            }
        }
    }

    fun deleteNote(note: Note) {
        viewModelScope.launch {
            _uiState.update { it.copy(isLoading = true, error = null) }
            try {
                deleteNote(note)
                if (_uiState.value.selectedNote?.id == note.id) {
                    _uiState.update { it.copy(selectedNote = null) }
                }
                _uiState.update { it.copy(isLoading = false) }
            } catch (e: Exception) {
                _uiState.update {
                    it.copy(error = e.message, isLoading = false)
                }
            }
        }
    }

    fun selectNote(note: Note) {
        _uiState.update { it.copy(selectedNote = note) }
    }

    fun clearError() {
        _uiState.update { it.copy(error = null) }
    }
}

// ---- UI ----
@Composable
fun RoomViewModelScreen(
    viewModel: NoteViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    var showAddDialog by remember { mutableStateOf(false) }
    var showEditDialog by remember { mutableStateOf(false) }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("📝 Notes") },
                actions = {
                    IconButton(onClick = { viewModel.toggleFavorites() }) {
                        Icon(
                            if (uiState.isShowingFavorites) Icons.Default.Star else Icons.Default.StarBorder,
                            contentDescription = "Favorites"
                        )
                    }
                    IconButton(onClick = { showAddDialog = true }) {
                        Icon(Icons.Default.Add, contentDescription = "Add Note")
                    }
                }
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp)
        ) {
            // ---- Search ----
            OutlinedTextField(
                value = uiState.searchQuery,
                onValueChange = { viewModel.search(it) },
                label = { Text("Search notes...") },
                leadingIcon = { Icon(Icons.Default.Search, null) },
                modifier = Modifier.fillMaxWidth()
            )

            Spacer(modifier = Modifier.height(8.dp))

            // ---- Error ----
            if (uiState.error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(uiState.error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                        Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                    }
                }
            }

            // ---- Selected note ----
            if (uiState.selectedNote != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.SpaceBetween
                        ) {
                            Text(
                                uiState.selectedNote?.title ?: "",
                                style = MaterialTheme.typography.titleLarge
                            )
                            IconButton(onClick = { 
                                uiState.selectedNote?.let { 
                                    viewModel.toggleFavorite(it.id)
                                }
                            }) {
                                Icon(
                                    if (uiState.selectedNote?.isFavorite == true) Icons.Default.Star else Icons.Default.StarBorder,
                                    null
                                )
                            }
                        }
                        Text(
                            uiState.selectedNote?.content ?: "",
                            style = MaterialTheme.typography.bodyMedium
                        )
                        Text(
                            "Created: ${java.text.SimpleDateFormat("MMM dd, yyyy HH:mm", java.util.Locale.getDefault())
                                .format(java.util.Date(uiState.selectedNote?.timestamp ?: 0))}",
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Button(
                                onClick = { showEditDialog = true },
                                modifier = Modifier.weight(1f)
                            ) { Text("Edit") }
                            Button(
                                onClick = {
                                    uiState.selectedNote?.let {
                                        viewModel.deleteNote(it)
                                    }
                                },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.error
                                )
                            ) { Text("Delete") }
                        }
                    }
                }
                Spacer(modifier = Modifier.height(8.dp))
            }

            // ---- Notes list ----
            LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                items(uiState.filteredNotes) { note ->
                    NoteCard(
                        note = note,
                        onClick = { viewModel.selectNote(note) },
                        onFavoriteToggle = { viewModel.toggleFavorite(note.id) }
                    )
                }
            }

            Text(
                text = "${uiState.filteredNotes.size} notes",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
    }

    if (showAddDialog) {
        AddNoteDialog(
            onDismiss = { showAddDialog = false },
            onAdd = { title, content ->
                viewModel.addNote(title, content)
                showAddDialog = false
            }
        )
    }

    if (showEditDialog && uiState.selectedNote != null) {
        EditNoteDialog(
            note = uiState.selectedNote!!,
            onDismiss = { showEditDialog = false },
            onSave = { title, content ->
                val note = uiState.selectedNote!!.copy(
                    title = title,
                    content = content
                )
                viewModel.updateNote(note)
                showEditDialog = false
            }
        )
    }
}

@Composable
fun NoteCard(
    note: Note,
    onClick: () -> Unit,
    onFavoriteToggle: () -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable { onClick() },
        elevation = CardDefaults.cardElevation(2.dp)
    ) {
        Row(
            modifier = Modifier.fillMaxWidth().padding(8.dp),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    note.title,
                    style = MaterialTheme.typography.titleMedium,
                    maxLines = 1,
                    overflow = TextOverflow.Ellipsis
                )
                Text(
                    note.content,
                    style = MaterialTheme.typography.bodySmall,
                    maxLines = 2,
                    overflow = TextOverflow.Ellipsis
                )
            }
            IconButton(onClick = onFavoriteToggle) {
                Icon(
                    if (note.isFavorite) Icons.Default.Star else Icons.Default.StarBorder,
                    null
                )
            }
        }
    }
}

@Composable
fun AddNoteDialog(
    onDismiss: () -> Unit,
    onAdd: (String, String) -> Unit
) {
    var title by remember { mutableStateOf("") }
    var content by remember { mutableStateOf("") }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Add Note") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = content,
                    onValueChange = { content = it },
                    label = { Text("Content") },
                    modifier = Modifier.fillMaxWidth()
                )
            }
        },
        confirmButton = {
            TextButton(
                onClick = { onAdd(title, content) },
                enabled = title.isNotBlank() && content.isNotBlank()
            ) { Text("Add") }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        }
    )
}

@Composable
fun EditNoteDialog(
    note: Note,
    onDismiss: () -> Unit,
    onSave: (String, String) -> Unit
) {
    var title by remember { mutableStateOf(note.title) }
    var content by remember { mutableStateOf(note.content) }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Edit Note") },
        text = {
            Column(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = title,
                    onValueChange = { title = it },
                    label = { Text("Title") },
                    modifier = Modifier.fillMaxWidth()
                )
                OutlinedTextField(
                    value = content,
                    onValueChange = { content = it },
                    label = { Text("Content") },
                    modifier = Modifier.fillMaxWidth()
                )
            }
        },
        confirmButton = {
            TextButton(
                onClick = { onSave(title, content) },
                enabled = title.isNotBlank() && content.isNotBlank()
            ) { Text("Save") }
        },
        dismissButton = {
            TextButton(onClick = onDismiss) { Text("Cancel") }
        }
    )
}

